import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import api from '../../api/axios';
import { Plus, Search, Edit2, Trash2, Users } from 'lucide-react';
import { PageTemplate } from '../../components/layout/PageTemplate';

export const ElevesList = () => {
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState('');

  const { data, isLoading } = useQuery({
    queryKey: ['eleves', page, search],
    queryFn: async () => {
      // Simulate real data behavior if API is not fully seeded yet
      try {
        const res = await api.get('/eleves', {
          params: { page, limit: 10, search }
        });
        return res.data;
      } catch (err) {
        return { data: [], pagination: { totalPages: 1, page: 1 } };
      }
    }
  });

  const headerActions = (
    <button className="pt-btn-primary">
      <Plus />
      <span>Ajouter un élève</span>
    </button>
  );

  return (
    <PageTemplate
      title="Gestion des Élèves"
      subtitle="Liste et suivi de tous les élèves inscrits dans l'établissement"
      badge="2024–2025"
      icon={<Users />}
      headerActions={headerActions}
    >
      <div className="pt-toolbar">
        <div className="pt-search-wrap">
          <Search />
          <input
            type="text"
            placeholder="Rechercher un élève, matricule..."
            className="pt-search-input"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
      </div>

      <div className="pt-table-wrap">
        <table className="pt-table">
          <thead>
            <tr>
              <th>Matricule</th>
              <th>Nom et Prénom</th>
              <th>Sexe</th>
              <th>Statut</th>
              <th style={{ textAlign: 'right' }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {isLoading ? (
              <tr>
                <td colSpan={5} style={{ textAlign: 'center', padding: '40px 20px', color: '#9ca3af' }}>
                  Chargement des données...
                </td>
              </tr>
            ) : data?.data?.length === 0 ? (
              <tr>
                <td colSpan={5}>
                  <div className="pt-empty">
                    <div className="pt-empty-icon"><Users /></div>
                    <div className="pt-empty-title">Aucun élève trouvé</div>
                    <div className="pt-empty-desc">Essayez de modifier vos critères de recherche ou ajoutez un nouvel élève au système.</div>
                  </div>
                </td>
              </tr>
            ) : (
              data?.data?.map((eleve: any) => (
                <tr key={eleve.matricule}>
                  <td style={{ fontFamily: "'JetBrains Mono', monospace", fontWeight: 500, color: '#4b5563' }}>
                    #{eleve.matricule || Math.floor(Math.random() * 10000)}
                  </td>
                  <td style={{ fontWeight: 500 }}>
                    {eleve.nom} {eleve.prenom}
                  </td>
                  <td>{eleve.sexe}</td>
                  <td>
                    <span className={eleve.actif ? 'pt-badge-green' : 'pt-badge-red'}>
                      {eleve.actif ? 'Actif' : 'Inactif'}
                    </span>
                  </td>
                  <td style={{ textAlign: 'right' }}>
                    <div style={{ display: 'flex', gap: '12px', justifyContent: 'flex-end', color: '#9ca3af' }}>
                      <button style={{ cursor: 'pointer', border: 'none', background: 'none' }} title="Modifier">
                        <Edit2 size={16} />
                      </button>
                      <button style={{ cursor: 'pointer', border: 'none', background: 'none' }} title="Supprimer">
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {data?.pagination && data.pagination.totalPages > 1 && (
        <div style={{ padding: '16px 20px', borderTop: '1px solid rgba(0,0,0,0.05)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <span style={{ fontSize: '13px', color: '#6b7280' }}>
            Page {data.pagination.page} sur {data.pagination.totalPages}
          </span>
          <div style={{ display: 'flex', gap: '8px' }}>
            <button 
              disabled={page === 1}
              onClick={() => setPage(p => p - 1)}
              style={{ padding: '6px 12px', borderRadius: '6px', border: '1px solid #e5e7eb', background: '#fff', fontSize: '13px', cursor: 'pointer' }}
            >
              Précédent
            </button>
            <button 
              disabled={page === data.pagination.totalPages}
              onClick={() => setPage(p => p + 1)}
              style={{ padding: '6px 12px', borderRadius: '6px', border: '1px solid #e5e7eb', background: '#fff', fontSize: '13px', cursor: 'pointer' }}
            >
              Suivant
            </button>
          </div>
        </div>
      )}
    </PageTemplate>
  );
};
